import requests
from bs4 import BeautifulSoup

class ConfluenceAdapter:
    """Ingest pages from a Confluence Cloud space."""

    def __init__(self, base_url: str, token: str,
                 space_key: str, access_level: str = "internal"):
        self.base_url = base_url.rstrip("/")
        self.session = requests.Session()
        self.session.headers["Authorization"] = f"Bearer {token}"
        self.space_key = space_key
        self.access_level = access_level

    def _pages(self):
        start = 0
        while True:
            r = self.session.get(
                f"{self.base_url}/rest/api/content",
                params={"spaceKey": self.space_key, "expand": "version,body.storage",
                        "start": start, "limit": 50}
            ).json()
            yield from r["results"]
            if r["start"] + len(r["results"]) >= r["size"]:
                break
            start += 50

    def iter_documents(self):
        for page in self._pages():
            html = page["body"]["storage"]["value"]
            text = BeautifulSoup(html, "html.parser").get_text(separator="\n")
            doc_id = hashlib.sha256(
                f"confluence:{page['id']}".encode()
            ).hexdigest()[:16]
            yield {
                "repo":           f"confluence-{self.space_key}",
                "doc_path":       page["title"],
                "doc_id":         doc_id,
                "text":           text,
                "doc_type":       "confluence",
                "access_level":   self.access_level,
                "team_labels":    [],
                "source_updated_at": datetime.fromisoformat(
                    page["version"]["when"].replace("Z", "+00:00")
                ),
            }

import cohere
from qdrant_client import QdrantClient
from qdrant_client.models import PointStruct, VectorParams, Distance

co = cohere.Client("COHERE_API_KEY")
qdrant = QdrantClient(host="localhost", port=6333)

COLLECTION = "knowledge_base"
EMBED_MODEL = "embed-english-v3.0"
BATCH_SIZE  = 96

def embed_batch(texts: list[str]) -> list[list[float]]:
    resp = co.embed(
        texts=texts,
        model=EMBED_MODEL,
        input_type="search_document",
    )
    return resp.embeddings

def upsert_chunks(chunks: list[dict]):
    """chunks: list of {id, text, embedding, metadata}"""
    points = [
        PointStruct(
            id=c["id"],
            vector=c["embedding"],
            payload={k: v for k, v in c["metadata"].items()}
        )
        for c in chunks
    ]
    qdrant.upsert(collection_name=COLLECTION, points=points)

def run_pipeline(adapters: list, chunker):
    buffer: list[dict] = []
    for adapter in adapters:
        for doc in adapter.iter_documents():
            for i, chunk_text in enumerate(chunker.split(doc["text"])):
                doc_id = doc["doc_id"]
                chunk_id = int(hashlib.sha256(
                    f"{doc_id}:{i}".encode()
                ).hexdigest()[:8], 16)  # deterministic uint
                buffer.append({
                    "id":   chunk_id,
                    "text": chunk_text,
                    "metadata": {
                        **{k: doc[k] for k in
                           ("repo","doc_path","doc_id","doc_type","access_level")},
                        "chunk_index":        i,
                        "embedding_model":    EMBED_MODEL,
                        "embedding_version":  "v2",
                        "source_updated_at":  doc["source_updated_at"].isoformat(),
                    }
                })
                if len(buffer) >= BATCH_SIZE:
                    texts = [c["text"] for c in buffer]
                    embs  = embed_batch(texts)
                    for c, emb in zip(buffer, embs):
                        c["embedding"] = emb
                    upsert_chunks(buffer)
                    buffer.clear()
    if buffer:
        embs = embed_batch([c["text"] for c in buffer])
        for c, emb in zip(buffer, embs):
            c["embedding"] = emb
        upsert_chunks(buffer)

def build_context(hits: list[dict], max_tokens: int = 3000) -> str:
    """Group hits by repo, truncate to token budget, add citations."""
    by_repo: dict[str, list] = {}
    for h in hits:
        by_repo.setdefault(h["repo"], []).append(h)

    sections = []
    for repo, chunks in by_repo.items():
        header = f"### {repo}"
        body_parts = []
        for c in chunks:
            citation = f"[{c['doc_path']}]"
            body_parts.append(f"{citation}\n{c['text'].strip()}")
        sections.append(header + "\n\n" + "\n\n---\n\n".join(body_parts))

    full = "\n\n".join(sections)
    # Rough token estimate: 4 chars ≈ 1 token
    if len(full) > max_tokens * 4:
        full = full[:max_tokens * 4] + "\n\n[context truncated]"
    return full


def answer_with_context(user_query: str, hits: list[dict], claude_client) -> str:
    context = build_context(hits)
    message = claude_client.messages.create(
        model="claude-opus-4-8",
        max_tokens=1024,
        messages=[{
            "role": "user",
            "content": (
                f"Using only the information below, answer the question.\n\n"
                f"{context}\n\n"
                f"Question: {user_query}"
            )
        }]
    )
    return message.content[0].text
